preflight.run:
$ErrorActionPreference = "Stop"
$PSNativeCommandUseErrorActionPreference = $true
if ($env:SDKWORK_PACKAGE_PLATFORM -eq "linux") {
  sudo apt-get update
  sudo apt-get install -y libwebkit2gtk-4.1-dev libgtk-3-dev libayatana-appindicator3-dev librsvg2-dev patchelf libssl-dev
} elseif ($env:SDKWORK_PACKAGE_PLATFORM -eq "macos") {
  $rustTarget = if ($env:SDKWORK_PACKAGE_ARCHITECTURE -eq "arm64") { "aarch64-apple-darwin" } else { "x86_64-apple-darwin" }
  rustup target add $rustTarget
}

package.run:
$ErrorActionPreference = "Stop"
$PSNativeCommandUseErrorActionPreference = $true
$args = @("--config", "src-tauri/tauri.prod.conf.json")
if ($env:SDKWORK_PACKAGE_PLATFORM -eq "linux") {
  if ($env:SDKWORK_PACKAGE_FORMAT -eq "deb") {
    $args += @("--bundles", "deb")
  } elseif ($env:SDKWORK_PACKAGE_FORMAT -eq "appimage") {
    $args += @("--bundles", "appimage")
  } else {
    throw "Unsupported Magic Studio Linux package format $env:SDKWORK_PACKAGE_FORMAT"
  }
} elseif ($env:SDKWORK_PACKAGE_PLATFORM -eq "windows") {
  if ($env:SDKWORK_PACKAGE_FORMAT -ne "exe") {
    throw "Unsupported Magic Studio Windows package format $env:SDKWORK_PACKAGE_FORMAT"
  }
  $args += @("--bundles", "nsis")
} elseif ($env:SDKWORK_PACKAGE_PLATFORM -eq "macos") {
  if ($env:SDKWORK_PACKAGE_FORMAT -ne "dmg") {
    throw "Unsupported Magic Studio macOS package format $env:SDKWORK_PACKAGE_FORMAT"
  }
  $rustTarget = if ($env:SDKWORK_PACKAGE_ARCHITECTURE -eq "arm64") { "aarch64-apple-darwin" } else { "x86_64-apple-darwin" }
  $args += @("--target", $rustTarget, "--bundles", "dmg")
} else {
  throw "Unsupported Magic Studio desktop platform $env:SDKWORK_PACKAGE_PLATFORM"
}
pnpm exec tauri build @args

validate.run:
$ErrorActionPreference = "Stop"
$artifactGlob = switch ($env:SDKWORK_PACKAGE_ID) {
  "linux-debian-x64-desktop-deb" { "src-tauri/target/release/bundle/deb/*.deb" }
  "linux-x64-desktop-appimage" { "src-tauri/target/release/bundle/appimage/*.AppImage" }
  "windows-x64-desktop-exe" { "src-tauri/target/release/bundle/nsis/*.exe" }
  "macos-arm64-desktop-dmg" { "src-tauri/target/aarch64-apple-darwin/release/bundle/dmg/*.dmg" }
  "macos-x64-desktop-dmg" { "src-tauri/target/x86_64-apple-darwin/release/bundle/dmg/*.dmg" }
  default { throw "Unsupported Magic Studio package id $env:SDKWORK_PACKAGE_ID" }
}
$artifacts = Get-ChildItem -Path $artifactGlob -File -ErrorAction SilentlyContinue
if (-not $artifacts) {
  throw "Missing built artifact for $env:SDKWORK_PACKAGE_ID matching $artifactGlob"
}
foreach ($artifact in $artifacts) {
  if ($artifact.Length -le 0) {
    throw "Built artifact is empty: $($artifact.FullName)"
  }
  Write-Host "Validated $($artifact.FullName)"
}
